                                    ? 'bg-bunny-red text-white rounded-tr-sm shadow-lg shadow-bunny-red/20' 
                                    : 'bg-white text-bunny-dark rounded-tl-sm shadow-lg'
                                }`}>
                                    {msg.text}
                                </div>
                            </div>
